static uint32_t calculate_checksum(struct system_config *cfg)
{
    uint32_t sum = 0;
    uint8_t *ptr = (uint8_t *)cfg;
    size_t len = sizeof(struct system_config) - sizeof(uint32_t);
    
    for (size_t i = 0; i < len; i++) {
        sum += ptr[i];
    }
    
    return sum;
}

static bool verify_privilege(struct task_context *ctx, enum privilege_level required)
{
    if (ctx->privilege >= required) {
        LOG_INF("Task %s (ID: %u) privilege check PASSED (has: %d, needs: %d)",
                ctx->name, ctx->task_id, ctx->privilege, required);
        return true;
    }
    
    LOG_WRN("Task %s (ID: %u) privilege check FAILED (has: %d, needs: %d)",
            ctx->name, ctx->task_id, ctx->privilege, required);
    return false;
}

static int admin_flash_write(uint32_t offset, const void *data, size_t len)
{
    const struct device *flash_dev = FLASH_DEVICE;
    int ret;
    
    if (!device_is_ready(flash_dev)) {
        LOG_ERR("Flash device not ready");
        return -ENODEV;
    }
    
    LOG_INF("Admin: Erasing flash at offset 0x%x, size %u", offset, len);
    ret = flash_erase(flash_dev, FLASH_OFFSET + offset, len);
    if (ret != 0) {
        LOG_ERR("Flash erase failed: %d", ret);
        return ret;
    }
    
    LOG_INF("Admin: Writing %u bytes to flash at offset 0x%x", len, offset);
    ret = flash_write(flash_dev, FLASH_OFFSET + offset, data, len);
    if (ret != 0) {
        LOG_ERR("Flash write failed: %d", ret);
        return ret;
    }
    
    LOG_INF("Admin: Flash write completed successfully");
    return 0;
}

static int admin_modify_config(const void *new_config_data, size_t len)
{
    int ret;
    
    if (len != sizeof(struct system_config)) {
        LOG_ERR("Invalid config size: %u (expected %u)", len, sizeof(struct system_config));
        return -EINVAL;
    }
    
    k_mutex_lock(&config_mutex, K_FOREVER);
    
    memcpy(&current_config, new_config_data, sizeof(struct system_config));
    current_config.checksum = calculate_checksum(&current_config);
    
    LOG_INF("Admin: System config modified");
    LOG_INF("  Magic: 0x%08X", current_config.magic);
    LOG_INF("  Version: %u", current_config.version);
    LOG_INF("  Timeout: %u ms", current_config.timeout_ms);
    LOG_INF("  Flags: 0x%08X", current_config.flags);
    LOG_INF("  Name: %s", current_config.name);
    LOG_INF("  Checksum: 0x%08X", current_config.checksum);
    
    ret = admin_flash_write(0, &current_config, sizeof(current_config));
    
    k_mutex_unlock(&config_mutex);
    
    return ret;
}

static int admin_get_system_info(void)
{
    k_mutex_lock(&config_mutex, K_FOREVER);
    
    LOG_INF("System Information:");
    LOG_INF("  Config Magic: 0x%08X", current_config.magic);
    LOG_INF("  Config Version: %u", current_config.version);
    LOG_INF("  System Name: %s", current_config.name);
    LOG_INF("  Timeout: %u ms", current_config.timeout_ms);
    LOG_INF("  Flags: 0x%08X", current_config.flags);
    
    k_mutex_unlock(&config_mutex);
    
    return 0;
}

static void process_privilege_request(struct privilege_request *req)
{
    int result = 0;
    
    LOG_INF("Processing privilege request from task %u, operation %d", 
            req->task_id, req->op_type);
    
    switch (req->op_type) {
    case OP_FLASH_WRITE:
        result = admin_flash_write(req->offset, req->data, req->data_len);
        break;
        
    case OP_CONFIG_MODIFY:
        result = admin_modify_config(req->data, req->data_len);
        break;
        
    case OP_SYSTEM_INFO:
        result = admin_get_system_info();
        break;
        
    default:
        LOG_ERR("Unknown operation type: %d", req->op_type);
        result = -EINVAL;
        break;
    }
    
    req->result = result;
    
    if (req->response_sem) {
        k_sem_give(req->response_sem);
    }
}

static void admin_task(void *p1, void *p2, void *p3)
{
    struct task_context ctx = {
        .task_id = 1,
        .privilege = PRIV_ADMIN,
        .name = "AdminTask"
    };
    
    struct privilege_request req;
    
    LOG_INF("Admin task started with privilege level: ADMIN");
    
    while (1) {
        if (k_msgq_get(&privilege_queue, &req, K_FOREVER) == 0) {
            LOG_INF("Admin task received privilege request");
            process_privilege_request(&req);
        }
    }
}

static int user_request_operation(struct task_context *ctx, enum operation_type op_type,
                                  void *data, size_t data_len, uint32_t offset)
{
    struct privilege_request req;
    struct k_sem response_sem;
    int ret;
    
    LOG_INF("User task %s requesting operation %d", ctx->name, op_type);
    
    if (verify_privilege(ctx, PRIV_ADMIN)) {
        LOG_WRN("Task has admin privilege but using request mechanism");
    }
    
    k_sem_init(&response_sem, 0, 1);
    
    req.op_type = op_type;
    req.task_id = ctx->task_id;
    req.data = data;
    req.data_len = data_len;
    req.offset = offset;
    req.response_sem = &response_sem;
    req.result = 0;
    
    ret = k_msgq_put(&privilege_queue, &req, K_NO_WAIT);
    if (ret != 0) {
        LOG_ERR("Failed to queue privilege request: %d", ret);
        return ret;
    }
    
    LOG_INF("Waiting for admin task to process request...");
    k_sem_take(&response_sem, K_FOREVER);
    
    LOG_INF("Request completed with result: %d", req.result);
    return req.result;
}

